-- Este seed crea el tenant de prueba para desarrollo.
-- En producción, los tenants se crean via la app.

-- Tenant de prueba
insert into tenants (id, slug, status) values
('00000000-0000-0000-0000-000000000001', 'offthehook', 'active')
on conflict (slug) do nothing;

